import{_ as r,o as a,c as t,ag as i}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"Awesome Web Archiving","description":"","frontmatter":{},"headers":[],"relativePath":"web-archiving/awesome-web-archiving.md","filePath":"web-archiving/awesome-web-archiving.md"}'),o={name:"web-archiving/awesome-web-archiving.md"};function l(n,e,s,h,c,b){return a(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="awesome-web-archiving" tabindex="-1">Awesome Web Archiving <a class="header-anchor" href="#awesome-web-archiving" aria-label="Permalink to &quot;Awesome Web Archiving&quot;">​</a></h1><p>Web archiving is the process of collecting portions of the World Wide Web to ensure the information is preserved in an archive for future researchers, historians, and the public. Web archivists typically employ Web crawlers for automated capture due to the massive scale of the Web. Ever-evolving Web standards require continuous evolution of archiving tools to keep up with the changes in Web technologies to ensure reliable and meaningful capture and replay of archived web pages.</p><h2 id="contents" tabindex="-1">Contents <a class="header-anchor" href="#contents" aria-label="Permalink to &quot;Contents&quot;">​</a></h2><ul><li>Training/Documentation</li><li>Resources for Web Publishers</li><li>Tools &amp; Software <ul><li>Acquisition</li><li>Replay</li><li>Search &amp; Discovery</li><li>Utilities</li><li>WARC I/O Libraries</li><li>Analysis</li><li>Quality Assurance</li><li>Curation</li></ul></li><li>Community Resources <ul><li>Other Awesome Lists</li><li>Blogs and Scholarship</li><li>Mailing Lists</li><li>Slack</li><li>Twitter</li></ul></li></ul><h3 id="training-documentation" tabindex="-1">Training/Documentation <a class="header-anchor" href="#training-documentation" aria-label="Permalink to &quot;Training/Documentation&quot;">​</a></h3><ul><li>Introductions to web archiving concepts: <ul><li><a href="https://youtu.be/ubDHY-ynWi0" target="_blank" rel="noreferrer">What is a web archive?</a> - A video from <a href="https://www.youtube.com/channel/UCJukhTSw8VRj-VNTpBcqWkw" target="_blank" rel="noreferrer">the UK Web Archive YouTube Channel</a></li><li><a href="https://en.wikipedia.org/wiki/List_of_Web_archiving_initiatives" target="_blank" rel="noreferrer">Wikipedia&#39;s List of Web Archiving Initiatives</a></li><li><a href="https://support.archive-it.org/hc/en-us/articles/208111686-Glossary-of-Archive-It-and-Web-Archiving-Terms" target="_blank" rel="noreferrer">Glossary of Archive-It and Web Archiving Terms</a></li><li><a href="https://archive-it.org/blog/post/announcing-the-web-archiving-life-cycle-model/" target="_blank" rel="noreferrer">The Web Archiving Lifecycle Model</a> - The Web Archiving Lifecycle Model is an attempt to incorporate the technological and programmatic arms of the web archiving into a framework that will be relevant to any organization seeking to archive content from the web. Archive-It, the web archiving service from the Internet Archive, developed the model based on its work with memory institutions around the world.</li><li><a href="https://netpreserve.org/web-archiving/training-materials/" target="_blank" rel="noreferrer">Training materials: module for beginners (8 sessions)</a></li><li><a href="https://github.com/vphill/web-archiving-course" target="_blank" rel="noreferrer">UNT Web Archiving Course 2022</a></li><li><a href="https://cedwarc.github.io/" target="_blank" rel="noreferrer">Continuing Education to Advance Web Archiving (CEDWARC)</a></li></ul></li><li>The WARC Standard: <ul><li>The <a href="https://iipc.github.io/warc-specifications/" target="_blank" rel="noreferrer">warc-specifications</a> community HTML version of the official specification and hub for new proposals.</li><li>The <a href="http://bibnum.bnf.fr/WARC/" target="_blank" rel="noreferrer">official ISO 28500 WARC specification homepage</a>.</li></ul></li><li>For researchers using web archives: <ul><li><a href="https://glam-workbench.github.io/web-archives/" target="_blank" rel="noreferrer">GLAM Workbench: Web Archives</a> - See also <a href="https://netpreserveblog.wordpress.com/2020/05/28/asking-questions-with-web-archives/" target="_blank" rel="noreferrer">this related blog post on &#39;Asking questions with web archives&#39;</a>.</li><li><a href="https://aut.docs.archivesunleashed.org/" target="_blank" rel="noreferrer">Archives Unleashed Toolkit documentation</a></li><li><a href="https://sobre.arquivo.pt/en/tutorial-for-humanities-researchers-about-how-to-use-arquivo-pt/" target="_blank" rel="noreferrer">Tutorial for Humanities researchers about how to explore Arquivo.pt</a></li></ul></li></ul><h3 id="resources-for-web-publishers" tabindex="-1">Resources for Web Publishers <a class="header-anchor" href="#resources-for-web-publishers" aria-label="Permalink to &quot;Resources for Web Publishers&quot;">​</a></h3><p>These resources can help when working with individuals or organisations who publish on the web, and who want to make sure their site can be archived.</p><ul><li><a href="https://library.stanford.edu/projects/web-archiving/archivability" target="_blank" rel="noreferrer">Stanford Libraries&#39; Archivability pages</a></li><li>The <a href="http://archiveready.com/" target="_blank" rel="noreferrer">Archive Ready</a> tool, for estimating how likely a web page will be archived successfully.</li></ul><h3 id="tools-software" tabindex="-1">Tools &amp; Software <a class="header-anchor" href="#tools-software" aria-label="Permalink to &quot;Tools &amp; Software&quot;">​</a></h3><p>This list of tools and software is intended to briefly describe some of the most important and widely-used tools related to web archiving. For more details, we recommend you refer to (and contribute to!) these excellent resources from other groups:</p><ul><li><a href="https://github.com/archivers-space/research/tree/master/web_archiving" target="_blank" rel="noreferrer">Comparison of web archiving software</a></li><li><a href="https://github.com/edgi-govdata-archiving/awesome-website-change-monitoring" target="_blank" rel="noreferrer">Awesome Website Change Monitoring</a></li></ul><h4 id="acquisition" tabindex="-1">Acquisition <a class="header-anchor" href="#acquisition" aria-label="Permalink to &quot;Acquisition&quot;">​</a></h4><ul><li><a href="https://github.com/pirate/ArchiveBox" target="_blank" rel="noreferrer">ArchiveBox</a> - A tool which maintains an additive archive from RSS feeds, bookmarks, and links using wget, Chrome headless, and other methods (formerly <code>Bookmark Archiver</code>). <em>(In Development)</em></li><li><a href="https://github.com/oduwsdl/archivenow" target="_blank" rel="noreferrer">archivenow</a> - A <a href="http://ws-dl.blogspot.com/2017/02/2017-02-22-archive-now-archivenow.html" target="_blank" rel="noreferrer">Python library</a> to push web resources into on-demand web archives. <em>(Stable)</em></li><li><a href="https://archiveweb.page" target="_blank" rel="noreferrer">ArchiveWeb.Page</a> - A plugin for Chrome and other Chromium based browsers that lets you interactively archive web pages, replay them, and export them as WARC data. Also available as an Electron based desktop application.</li><li><a href="https://github.com/bellingcat/auto-archiver" target="_blank" rel="noreferrer">Auto Archiver</a> - Python script to automatically archive social media posts, videos, and images from a Google Sheets document. Read the <a href="https://www.bellingcat.com/resources/2022/09/22/preserve-vital-online-content-with-bellingcats-auto-archiver-tool/" target="_blank" rel="noreferrer">article about Auto Archiver on bellingcat.com</a>.</li><li><a href="https://github.com/webrecorder/browsertrix-crawler" target="_blank" rel="noreferrer">Browsertrix Crawler</a> - A Chrome based high-fidelity crawling system, designed to run a complex, customizable browser-based crawl in a single Docker container.</li><li><a href="https://github.com/internetarchive/brozzler" target="_blank" rel="noreferrer">Brozzler</a> - A distributed web crawler (爬虫) that uses a real browser (Chrome or Chromium) to fetch pages and embedded urls and to extract links. <em>(Stable)</em></li><li><a href="https://github.com/wabarc/cairn" target="_blank" rel="noreferrer">Cairn</a> - A npm package and CLI tool for saving webpages. <em>(Stable)</em></li><li><a href="https://github.com/CGamesPlay/chronicler" target="_blank" rel="noreferrer">Chronicler</a> - Web browser with record and replay functionality. <em>(In Development)</em></li><li><a href="https://git.autistici.org/ale/crawl" target="_blank" rel="noreferrer">Crawl</a> - A simple web crawler in Golang. <em>(Stable)</em></li><li><a href="https://github.com/promyloph/crocoite" target="_blank" rel="noreferrer">crocoite</a> - Crawl websites using headless Google Chrome/Chromium and save resources, static DOM snapshot and page screenshots to WARC files. <em>(In Development)</em></li><li><a href="https://github.com/dosyago/DiskerNet" target="_blank" rel="noreferrer">DiskerNet</a> - A non-WARC-based tool which hooks into the Chrome browser and archives everything you browse making it available for offline replay. <em>(In Development)</em></li><li><a href="https://github.com/justinlittman/fbarc" target="_blank" rel="noreferrer">F(b)arc</a> - A commandline tool and Python library for archiving data from <a href="https://www.facebook.com/" target="_blank" rel="noreferrer">Facebook</a> using the <a href="https://developers.facebook.com/docs/graph-api" target="_blank" rel="noreferrer">Graph API</a>. <em>(Stable)</em></li><li><a href="https://github.com/WebMemex/freeze-dry" target="_blank" rel="noreferrer">freeze-dry</a> - JavaScript library to turn page into static, self-contained HTML document; useful for browser extensions. <em>(In Development)</em></li><li><a href="https://github.com/ArchiveTeam/grab-site" target="_blank" rel="noreferrer">grab-site</a> - The archivist&#39;s web crawler: WARC output, dashboard for all crawls, dynamic ignore patterns. <em>(Stable)</em></li><li><a href="https://github.com/internetarchive/heritrix3/wiki" target="_blank" rel="noreferrer">Heritrix</a> - An open source, extensible, web-scale, archival quality web crawler. <em>(Stable)</em><ul><li><a href="https://github.com/internetarchive/heritrix3/discussions/categories/q-a" target="_blank" rel="noreferrer">Heritrix Q&amp;A</a> - A discussion forum for asking questions and getting answers about using Heritrix.</li><li><a href="https://github.com/web-archive-group/heritrix-walkthrough" target="_blank" rel="noreferrer">Heritrix Walkthrough</a> <em>(In Development)</em></li></ul></li><li><a href="https://github.com/steffenfritz/html2warc" target="_blank" rel="noreferrer">html2warc</a> - A simple script to convert offline data into a single WARC file. <em>(Stable)</em></li><li><a href="http://www.httrack.com/" target="_blank" rel="noreferrer">HTTrack</a> - An open source website copying utility. <em>(Stable)</em></li><li><a href="https://github.com/Y2Z/monolith" target="_blank" rel="noreferrer">monolith</a> - CLI tool to save a web page as a single HTML file. <em>(Stable)</em></li><li><a href="https://github.com/go-shiori/obelisk" target="_blank" rel="noreferrer">Obelisk</a> - Go package and CLI tool for saving web page as single HTML file. <em>(Stable)</em></li><li><a href="https://github.com/harvard-lil/scoop" target="_blank" rel="noreferrer">Scoop</a> - High-fidelity, browser-based, single-page web archiving library and CLI for witnessing the web. <em>(Stable)</em></li><li><a href="https://github.com/gildas-lormeau/SingleFile" target="_blank" rel="noreferrer">SingleFile</a> - Browser extension for Firefox/Chrome and CLI tool to save a faithful copy of a complete page as a single HTML file. <em>(Stable)</em></li><li><a href="http://mementoweb.github.com/SiteStory/" target="_blank" rel="noreferrer">SiteStory</a> - A transactional archive that selectively captures and stores transactions that take place between a web client (browser) and a web server. <em>(Stable)</em></li><li><a href="https://gwu-libraries.github.io/sfm-ui/" target="_blank" rel="noreferrer">Social Feed Manager</a> - Open source software that enables users to create social media collections from Twitter, Tumblr, Flickr, and Sina Weibo public APIs. <em>(Stable)</em></li><li><a href="https://github.com/N0taN3rd/Squidwarc" target="_blank" rel="noreferrer">Squidwarc</a> - An <a href="http://ws-dl.blogspot.com/2017/07/2017-07-24-replacing-heritrix-with.html" target="_blank" rel="noreferrer">open source, high-fidelity, page interacting</a> archival crawler that uses Chrome or Chrome Headless directly. <em>(In Development)</em></li><li><a href="http://stormcrawler.net/" target="_blank" rel="noreferrer">StormCrawler</a> - A collection of resources for building low-latency, scalable web crawlers on Apache Storm. <em>(Stable)</em></li><li><a href="https://github.com/docnow/twarc" target="_blank" rel="noreferrer">twarc</a> - A command line tool and Python library for archiving Twitter JSON data. <em>(Stable)</em></li><li><a href="https://github.com/machawk1/wail" target="_blank" rel="noreferrer">WAIL</a> - A graphical user interface (GUI) atop multiple web archiving tools intended to be used as an easy way for anyone to preserve and replay web pages; <a href="https://machawk1.github.io/wail/" target="_blank" rel="noreferrer">Python</a>, <a href="https://github.com/n0tan3rd/wail" target="_blank" rel="noreferrer">Electron</a>. <em>(Stable)</em></li><li><a href="https://github.com/internetarchive/warcprox" target="_blank" rel="noreferrer">Warcprox</a> - WARC-writing MITM HTTP/S proxy. <em>(Stable)</em></li><li><a href="http://matkelly.com/warcreate/" target="_blank" rel="noreferrer">WARCreate</a> - A <a href="https://www.google.com/intl/en/chrome/browser/" target="_blank" rel="noreferrer">Google Chrome</a> extension for archiving an individual webpage or website to a WARC file. <em>(Stable)</em></li><li><a href="https://github.com/peterk/warcworker" target="_blank" rel="noreferrer">Warcworker</a> - An open source, dockerized, queued, high fidelity web archiver based on Squidwarc with a simple web GUI. <em>(Stable)</em></li><li><a href="https://github.com/wabarc/wayback" target="_blank" rel="noreferrer">Wayback</a> - A toolkit for snapshot webpage to Internet Archive, archive.today, IPFS and beyond. <em>(Stable)</em></li><li><a href="https://github.com/akamhy/waybackpy" target="_blank" rel="noreferrer">Waybackpy</a> - Wayback Machine Save, CDX and availability API interface in Python and a command-line tool <em>(Stable)</em></li><li><a href="https://github.com/helgeho/Web2Warc" target="_blank" rel="noreferrer">Web2Warc</a> - An easy-to-use and highly customizable crawler that enables anyone to create their own little Web archives (WARC/CDX). <em>(Stable)</em></li><li><a href="https://webcuratortool.org" target="_blank" rel="noreferrer">Web Curator Tool</a> - Open-source workflow management for selective web archiving. <em>(Stable)</em></li><li><a href="https://github.com/WebMemex" target="_blank" rel="noreferrer">WebMemex</a> - Browser extension for Firefox and Chrome which lets you archive web pages you visit. <em>(In Development)</em></li><li><a href="https://webrecorder.io/" target="_blank" rel="noreferrer">Webrecorder</a> - Create high-fidelity, interactive recordings of any web site you browse. <em>(Stable)</em></li><li><a href="http://www.gnu.org/software/wget/" target="_blank" rel="noreferrer">Wget</a> - An open source file retrieval utility that, as of <a href="http://www.archiveteam.org/index.php?title=Wget_with_WARC_output" target="_blank" rel="noreferrer">version 1.14, supports writing warcs</a>. <em>(Stable)</em></li><li><a href="https://github.com/alard/wget-lua" target="_blank" rel="noreferrer">Wget-lua</a> - Wget with Lua extension. <em>(Stable)</em></li><li><a href="https://github.com/chfoo/wpull" target="_blank" rel="noreferrer">Wpull</a> - A Wget-compatible (or remake/clone/replacement/alternative) web downloader and crawler. <em>(Stable)</em></li></ul><h4 id="replay" tabindex="-1">Replay <a class="header-anchor" href="#replay" aria-label="Permalink to &quot;Replay&quot;">​</a></h4><ul><li><a href="https://github.com/oduwsdl/ipwb" target="_blank" rel="noreferrer">InterPlanetary Wayback (ipwb)</a> - Web Archive (WARC) indexing and replay using <a href="https://ipfs.io/" target="_blank" rel="noreferrer">IPFS</a>.</li><li><a href="https://github.com/iipc/openwayback/" target="_blank" rel="noreferrer">OpenWayback</a> - The open source project aimed to develop Wayback Machine, the key software used by web archives worldwide to play back archived websites in the user&#39;s browser. <em>(Stable)</em></li><li><a href="https://github.com/ikreymer/pywb" target="_blank" rel="noreferrer">PyWb</a> - A Python (2 and 3) implementation of web archival replay tools, sometimes also known as &#39;Wayback Machine&#39;. <em>(Stable)</em></li><li><a href="https://oduwsdl.github.io/Reconstructive/" target="_blank" rel="noreferrer">Reconstructive</a> - Reconstructive is a ServiceWorker module for client-side reconstruction of composite mementos by rerouting resource requests to corresponding archived copies (JavaScript).</li><li><a href="https://replayweb.page/" target="_blank" rel="noreferrer">ReplayWeb.Page</a> - A browser-based, fully client-side replay engine for both local and remote WARC files.</li><li><a href="https://github.com/iipc/warc2html" target="_blank" rel="noreferrer">warc2html</a> - Converts WARC files to static HTML suitable for browsing offline or rehosting.</li></ul><h4 id="search-discovery" tabindex="-1">Search &amp; Discovery <a class="header-anchor" href="#search-discovery" aria-label="Permalink to &quot;Search &amp; Discovery&quot;">​</a></h4><ul><li><a href="https://github.com/machawk1/mink" target="_blank" rel="noreferrer">Mink</a> - A <a href="https://www.google.com/intl/en/chrome/" target="_blank" rel="noreferrer">Google Chrome</a> extension for querying Memento aggregators while browsing and integrating live-archived web navigation. <em>(Stable)</em></li><li><a href="https://github.com/wabarc/playback" target="_blank" rel="noreferrer">playback</a> - A toolkit for searching archived webpages from <a href="https://web.archive.org" target="_blank" rel="noreferrer">Internet Archive</a>, <a href="https://archive.today" target="_blank" rel="noreferrer">archive.today</a>, <a href="http://timetravel.mementoweb.org" target="_blank" rel="noreferrer">Memento</a> and beyond. <em>(In Development)</em></li><li><a href="https://securitytrails.com/" target="_blank" rel="noreferrer">SecurityTrails</a> - Web based archive for WHOIS and DNS records. REST API available free of charge.</li><li><a href="http://tempas.l3s.de/v1" target="_blank" rel="noreferrer">Tempas v1</a> - Temporal web archive search based on <a href="https://en.wikipedia.org/wiki/Delicious_(website)" target="_blank" rel="noreferrer">Delicious</a> tags. <em>(Stable)</em></li><li><a href="http://tempas.l3s.de/v2" target="_blank" rel="noreferrer">Tempas v2</a> - Temporal web archive search based on links and anchor texts extracted from the German web from 1996 to 2013 (results are not limited to German pages, e.g., <a href="http://tempas.l3s.de/v2/query?q=obama&amp;from=2005&amp;to=2009" target="_blank" rel="noreferrer">Obama@2005-2009 in Tempas</a>). <em>(Stable)</em></li><li><a href="https://github.com/ukwa/webarchive-discovery" target="_blank" rel="noreferrer">webarchive-discovery</a> - WARC and ARC full-text indexing and discovery tools, with a number of associated tools capable of using the index shown below. <em>(Stable)</em><ul><li><a href="https://github.com/ukwa/shine" target="_blank" rel="noreferrer">Shine</a> - A prototype web archives exploration UI, developed with researchers as part of the <a href="https://buddah.projects.history.ac.uk/" target="_blank" rel="noreferrer">Big UK Domain Data for the Arts and Humanities project</a>. <em>(Stable)</em></li><li><a href="https://github.com/netarchivesuite/solrwayback" target="_blank" rel="noreferrer">SolrWayback</a> - A backend Java and frontend VUE JS project with freetext search and a build in playback engine. Require Warc files has been index with the Warc-Indexer. The web application also has a wide range of data visualization tools and data export tools that can be used on the whole webarchive. <a href="https://github.com/netarchivesuite/solrwayback/releases" target="_blank" rel="noreferrer">SolrWayback 4 Bundle release</a> contains all the software and dependencies in an out-of-the box solution that is easy to install.</li><li><a href="https://github.com/archivesunleashed/warclight" target="_blank" rel="noreferrer">Warclight</a> - A Project Blacklight based Rails engine that supports the discovery of web archives held in the WARC and ARC formats. <em>(In Development)</em></li><li><a href="https://github.com/webis-de/wasp" target="_blank" rel="noreferrer">Wasp</a> - A fully functional prototype of a personal <a href="http://ceur-ws.org/Vol-2167/paper6.pdf" target="_blank" rel="noreferrer">web archive and search system</a>. <em>(In Development)</em></li><li>Other possible options for building a front-end are listed in the <code>webarchive-discovery</code> wiki, <a href="https://github.com/ukwa/webarchive-discovery/wiki/Front-ends" target="_blank" rel="noreferrer">here</a>.</li></ul></li></ul><h4 id="utilities" tabindex="-1">Utilities <a class="header-anchor" href="#utilities" aria-label="Permalink to &quot;Utilities&quot;">​</a></h4><ul><li><a href="https://github.com/recrm/ArchiveTools" target="_blank" rel="noreferrer">ArchiveTools</a> - Collection of tools to extract and interact with WARC files (Python).</li><li><a href="https://github.com/nlnwa/gowarcserver" target="_blank" rel="noreferrer">gowarcserver</a> - <a href="https://github.com/dgraph-io/badger" target="_blank" rel="noreferrer">BadgerDB</a>-based capture index (CDX) and WARC record server, used to index and serve WARC files (Go).</li><li><a href="https://github.com/webrecorder/har2warc" target="_blank" rel="noreferrer">har2warc</a> - Convert HTTP Archive (HAR) -&gt; Web Archive (WARC) format (Python).</li><li><a href="http://httpreserve.info/" target="_blank" rel="noreferrer">httpreserve.info</a> - Service to return the status of a web page or save it to the Internet Archive. Returns JSON via browser or command line via CURL using GET (Golang Package). <em>(Stable)</em></li><li><a href="https://github.com/httpreserve/workbench" target="_blank" rel="noreferrer">HTTPreserve Workbench</a> - Tool and API to describe the status of a web page encoded in a simple JSON output describing current status, and earliest and latest links on wayback.org. Save a web page to the Internet Archive. Audit lists of URIs and output a CSV with the data described above (Golang). <em>(In Development)</em></li><li><a href="https://github.com/nla/httrack2warc" target="_blank" rel="noreferrer">httrack2warc</a> - Convert HTTrack archives to WARC format (Java).</li><li><a href="https://github.com/oduwsdl/MementoMap" target="_blank" rel="noreferrer">MementoMap</a> - A Tool to Summarize Web Archive Holdings (Python). <em>(In Development)</em></li><li><a href="https://github.com/oduwsdl/MemGator" target="_blank" rel="noreferrer">MemGator</a> - A Memento Aggregator CLI and Server (Golang). <em>(Stable)</em></li><li><a href="https://github.com/N0taN3rd/node-cdxj" target="_blank" rel="noreferrer">node-cdxj</a> - <a href="https://github.com/oduwsdl/ORS/wiki/CDXJ" target="_blank" rel="noreferrer">CDXJ</a> file parser (Node.js). <em>(Stable)</em></li><li><a href="https://github.com/nla/outbackcdx" target="_blank" rel="noreferrer">OutbackCDX</a> - RocksDB-based capture index (CDX) server supporting incremental updates and compression. Can be used as backend for OpenWayback, PyWb and <a href="https://github.com/ukwa/ukwa-heritrix/blob/master/src/main/java/uk/bl/wap/modules/uriuniqfilters/OutbackCDXRecentlySeenUriUniqFilter.java" target="_blank" rel="noreferrer">Heritrix</a>. <em>(Stable)</em></li><li><a href="https://github.com/unt-libraries/py-wasapi-client" target="_blank" rel="noreferrer">py-wasapi-client</a> - Command line application to download crawls from WASAPI (Python). <em>(Stable)</em></li><li><a href="https://archivebrowser.c3.cx/" target="_blank" rel="noreferrer">The Archive Browser</a> - The Archive Browser is a program that lets you browse the contents of archives, as well as extract them. It will let you open files from inside archives, and lets you preview them using Quick Look. WARC is supported (macOS only, Proprietary app).</li><li><a href="http://unarchiver.c3.cx/unarchiver" target="_blank" rel="noreferrer">The Unarchiver</a> - Program to extract the contents of many archive formats, inclusive of WARC, to a file system. Free variant of The Archive Browser (macOS only, Proprietary app).</li><li><a href="https://github.com/httpreserve/tikalinkextract" target="_blank" rel="noreferrer">tikalinkextract</a> - Extract hyperlinks as a seed for web archiving from folders of document types that can be parsed by Apache Tika (Golang, Apache Tika Server). <em>(In Development)</em></li><li><a href="https://github.com/sul-dlss/wasapi-downloader" target="_blank" rel="noreferrer">wasapi-downloader</a> - Java command line application to download crawls from WASAPI. <em>(Stable)</em></li><li><a href="https://nlnwa.github.io/warchaeology/" target="_blank" rel="noreferrer">Warchaeology</a> - Warchaeology is a collection of tools for inspecting, manipulating, deduplicating and validating WARC-files. <em>Stable</em></li><li><a href="https://gitlab.com/taricorp/warcdedupe" target="_blank" rel="noreferrer">warcdedupe</a> - WARC deduplication tool (and WARC library) written in Rust. (In Development)</li><li><a href="https://github.com/helgeho/WarcPartitioner" target="_blank" rel="noreferrer">WarcPartitioner</a> - Partition (W)ARC Files by MIME Type and Year. <em>(Stable)</em></li><li><a href="https://github.com/arcalex/warcrefs" target="_blank" rel="noreferrer">warcrefs</a> - Web archive deduplication tools. <em>Stable</em></li><li><a href="https://github.com/ikreymer/webarchive-indexing" target="_blank" rel="noreferrer">webarchive-indexing</a> - Tools for bulk indexing of WARC/ARC files on Hadoop, EMR or local file system.</li><li><a href="https://github.com/WikiTeam/wikiteam" target="_blank" rel="noreferrer">wikiteam</a> - Tools for downloading and preserving wikis. <em>(Stable)</em></li></ul><h4 id="warc-i-o-libraries" tabindex="-1">WARC I/O Libraries <a class="header-anchor" href="#warc-i-o-libraries" aria-label="Permalink to &quot;WARC I/O Libraries&quot;">​</a></h4><ul><li><a href="https://github.com/chatnoir-eu/chatnoir-resiliparse" target="_blank" rel="noreferrer">FastWARC</a> - A high-performance WARC parsing library (Python).</li><li><a href="https://github.com/helgeho/HadoopConcatGz" target="_blank" rel="noreferrer">HadoopConcatGz</a> - A Splitable Hadoop InputFormat for Concatenated GZIP Files (and <code>*.warc.gz</code>). <em>(Stable)</em></li><li><a href="https://github.com/iipc/jwarc" target="_blank" rel="noreferrer">jwarc</a> - Reading and write WARC files with a typesafe API (Java).</li><li><a href="https://sbforge.org/display/JWAT/JWAT" target="_blank" rel="noreferrer">Jwat</a> - Libraries and tools for reading/writing/validating WARC/ARC/GZIP files (Java). <em>(Stable)</em></li><li><a href="https://github.com/N0taN3rd/node-warc" target="_blank" rel="noreferrer">node-warc</a> - Parse WARC files or create WARC files using either <a href="https://electron.atom.io/" target="_blank" rel="noreferrer">Electron</a> or <a href="https://github.com/cyrus-and/chrome-remote-interface" target="_blank" rel="noreferrer">chrome-remote-interface</a> (Node.js). <em>(Stable)</em></li><li><a href="https://github.com/internetarchive/Sparkling" target="_blank" rel="noreferrer">Sparkling</a> - Internet Archive&#39;s Sparkling Data Processing Library. <em>(Stable)</em></li><li><a href="https://github.com/emmadickson/unwarcit" target="_blank" rel="noreferrer">Unwarcit</a> - Command line interface to unzip WARC and WACZ files (Python).</li><li><a href="https://github.com/chfoo/warcat" target="_blank" rel="noreferrer">Warcat</a> - Tool and library for handling Web ARChive (WARC) files (Python). <em>(Stable)</em></li><li><a href="https://github.com/webrecorder/warcio" target="_blank" rel="noreferrer">warcio</a> - Streaming WARC/ARC library for fast web archive IO (Python).</li><li><a href="https://github.com/internetarchive/warctools" target="_blank" rel="noreferrer">warctools</a> - Library to work with ARC and WARC files (Python).</li><li><a href="https://github.com/richardlehane/webarchive" target="_blank" rel="noreferrer">webarchive</a> - Golang readers for ARC and WARC webarchive formats (Golang).</li></ul><h4 id="analysis" tabindex="-1">Analysis <a class="header-anchor" href="#analysis" aria-label="Permalink to &quot;Analysis&quot;">​</a></h4><ul><li><a href="https://github.com/internetarchive/arch" target="_blank" rel="noreferrer">Archives Research Compute Hub</a> - Web application for distributed compute analysis of Archive-It web archive collections. <em>(Stable)</em></li><li><a href="https://github.com/helgeho/ArchiveSpark" target="_blank" rel="noreferrer">ArchiveSpark</a> - An Apache Spark framework (not only) for Web Archives that enables easy data processing, extraction as well as derivation. <em>(Stable)</em></li><li><a href="https://github.com/archivesunleashed/notebooks" target="_blank" rel="noreferrer">Archives Unleashed Notebooks</a> - Notebooks for working with web archives with the Archives Unleashed Toolkit, and derivatives generated by the Archives Unleashed Toolkit. <em>(Stable)</em></li><li><a href="https://github.com/archivesunleashed/aut" target="_blank" rel="noreferrer">Archives Unleashed Toolkit</a> - Archives Unleashed Toolkit (AUT) is an open-source platform for analyzing web archives with Apache Spark. <em>(Stable)</em></li><li><a href="https://github.com/archivesunleashed/twut" target="_blank" rel="noreferrer">Tweet Archives Unleashed Toolkit</a> - An open-source toolkit for analyzing line-oriented JSON Twitter archives with Apache Spark. <em>(In Development)</em></li></ul><h4 id="quality-assurance" tabindex="-1">Quality Assurance <a class="header-anchor" href="#quality-assurance" aria-label="Permalink to &quot;Quality Assurance&quot;">​</a></h4><ul><li><a href="https://chrome.google.com/webstore/detail/check-my-links/ojkcdipcgfaekbeaelaapakgnjflfglf" target="_blank" rel="noreferrer">Chrome Check My Links</a> - Browser extension: a link checker with more options.</li><li><a href="https://chrome.google.com/webstore/detail/link-checker/aibjbgmpmnidnmagaefhmcjhadpffaoi" target="_blank" rel="noreferrer">Chrome link checker</a> - Browser extension: basic link checker.</li><li><a href="https://chrome.google.com/webstore/detail/bpjdkodgnbfalgghnbeggfbfjpcfamkf/publish-accepted?hl=en-US&amp;gl=US" target="_blank" rel="noreferrer">Chrome link gopher</a> - Browser extension: link harvester on a page.</li><li><a href="https://chrome.google.com/webstore/detail/open-multiple-urls/oifijhaokejakekmnjmphonojcfkpbbh?hl=de" target="_blank" rel="noreferrer">Chrome Open Multiple URLs</a> - Browser extension: opens multiple URLs and also extracts URLs from text.</li><li><a href="https://chrome.google.com/webstore/detail/revolver-tabs/dlknooajieciikpedpldejhhijacnbda" target="_blank" rel="noreferrer">Chrome Revolver</a> - Browser extension: switches between browser tabs.</li><li><a href="https://github.com/lupoDharkael/flameshot" target="_blank" rel="noreferrer">FlameShot</a> - Screen capture and annotation on Ubuntu.</li><li><a href="https://www.playonlinux.com/en/" target="_blank" rel="noreferrer">PlayOnLinux</a> - For running Xenu and Notepad++ on Ubuntu.</li><li><a href="https://www.playonmac.com/en/" target="_blank" rel="noreferrer">PlayOnMac</a> - For running Xenu and Notepad++ on macOS.</li><li><a href="https://support.microsoft.com/en-gb/help/13776/windows-use-snipping-tool-to-capture-screenshots" target="_blank" rel="noreferrer">Windows Snipping Tool</a> - Windows built-in for partial screen capture and annotation. On macOS you can use Command + Shift + 4 (keyboard shortcut for taking partial screen capture).</li><li><a href="http://winebottler.kronenberg.org/" target="_blank" rel="noreferrer">WineBottler</a> - For running Xenu and Notepad++ on macOS.</li><li><a href="https://github.com/jordansissel/xdotool" target="_blank" rel="noreferrer">xDoTool</a> - Click automation on Ubuntu.</li><li><a href="http://home.snafu.de/tilman/xenulink.html" target="_blank" rel="noreferrer">Xenu</a> - Desktop link checker for Windows.</li></ul><h4 id="curation" tabindex="-1">Curation <a class="header-anchor" href="#curation" aria-label="Permalink to &quot;Curation&quot;">​</a></h4><ul><li><a href="https://robustlinks.mementoweb.org/zotero/" target="_blank" rel="noreferrer">Zotero Robust Links Extension</a> - A <a href="https://www.zotero.org/" target="_blank" rel="noreferrer">Zotero</a> extension that submits to and reads from web archives. Source <a href="https://github.com/lanl/Zotero-Robust-Links-Extension" target="_blank" rel="noreferrer">on GitHub</a>. Supercedes <a href="https://github.com/leonkt/zotero-memento" target="_blank" rel="noreferrer">leonkt/zotero-memento</a>.</li></ul><h3 id="community-resources" tabindex="-1">Community Resources <a class="header-anchor" href="#community-resources" aria-label="Permalink to &quot;Community Resources&quot;">​</a></h3><h4 id="other-awesome-lists" tabindex="-1">Other Awesome Lists <a class="header-anchor" href="#other-awesome-lists" aria-label="Permalink to &quot;Other Awesome Lists&quot;">​</a></h4><ul><li><a href="https://github.com/pirate/ArchiveBox/wiki/Web-Archiving-Community" target="_blank" rel="noreferrer">Web Archiving Community</a></li><li><a href="https://github.com/machawk1/awesome-memento" target="_blank" rel="noreferrer">Awesome Memento</a></li><li><a href="http://www.archiveteam.org/index.php?title=The_WARC_Ecosystem" target="_blank" rel="noreferrer">The WARC Ecosystem</a></li><li><a href="http://coptr.digipres.org/Category:Web_Crawl" target="_blank" rel="noreferrer">The Web Crawl section of COPTR</a></li></ul><h4 id="blogs-and-scholarship" tabindex="-1">Blogs and Scholarship <a class="header-anchor" href="#blogs-and-scholarship" aria-label="Permalink to &quot;Blogs and Scholarship&quot;">​</a></h4><ul><li><a href="https://netpreserveblog.wordpress.com/" target="_blank" rel="noreferrer">IIPC Blog</a></li><li><a href="https://webarchivingrt.wordpress.com/" target="_blank" rel="noreferrer">Web Archiving Roundtable</a> - Unofficial blog of the Web Archiving Roundtable of the <a href="https://www2.archivists.org/" target="_blank" rel="noreferrer">Society of American Archivists</a> maintained by the members of the Web Archiving Roundtable.</li><li><a href="https://www.uclpress.co.uk/products/84010" target="_blank" rel="noreferrer">The Web as History</a> - An open-source book that provides a conceptual overview to web archiving research, as well as several case studies.</li><li><a href="https://ws-dl.blogspot.com/" target="_blank" rel="noreferrer">WS-DL Blog</a> - Web Science and Digital Libraries Research Group blogs about various Web archiving related topics, scholarly work, and academic trip reports.</li><li><a href="https://blog.dshr.org/" target="_blank" rel="noreferrer">DSHR&#39;s Blog</a> - David Rosenthal regularly reviews and summarizes work done in the Digital Preservation field.</li><li><a href="https://blogs.bl.uk/webarchive/" target="_blank" rel="noreferrer">UK Web Archive Blog</a></li></ul><h4 id="mailing-lists" tabindex="-1">Mailing Lists <a class="header-anchor" href="#mailing-lists" aria-label="Permalink to &quot;Mailing Lists&quot;">​</a></h4><ul><li><a href="http://netpreserve.org/about-us/iipc-mailing-list/" target="_blank" rel="noreferrer">IIPC</a></li><li><a href="https://groups.google.com/g/openwayback-dev" target="_blank" rel="noreferrer">OpenWayback</a></li><li><a href="https://groups.google.com/g/wasapi-community" target="_blank" rel="noreferrer">WASAPI</a></li></ul><h4 id="slack" tabindex="-1">Slack <a class="header-anchor" href="#slack" aria-label="Permalink to &quot;Slack&quot;">​</a></h4><ul><li><a href="https://iipc.slack.com/" target="_blank" rel="noreferrer">IIPC Slack</a> - Ask <a href="https://twitter.com/NetPreserve?s=20" target="_blank" rel="noreferrer">@netpreserve</a> for access.</li><li><a href="https://archivesunleashed.slack.com/" target="_blank" rel="noreferrer">Archives Unleashed Slack</a> - <a href="https://docs.google.com/forms/d/e/1FAIpQLScXPIH0Ssw63yWqyMkUqHVYmz2-ItBMzHiJQ-sOlJwTA8u5AQ/viewform?usp=sf_link" target="_blank" rel="noreferrer">Fill out this request form</a> for access to a researcher group of people working with web archives.</li><li><a href="https://archivers.slack.com" target="_blank" rel="noreferrer">Archivers Slack</a> - <a href="https://archivers-slack.herokuapp.com/" target="_blank" rel="noreferrer">Invite yourself</a> to a multi-disciplinary effort for archiving projects run in affiliation with <a href="https://envirodatagov.org/archiving/" target="_blank" rel="noreferrer">EDGI</a> and <a href="http://datatogether.org/" target="_blank" rel="noreferrer">Data Together</a>.</li></ul><h4 id="twitter" tabindex="-1">Twitter <a class="header-anchor" href="#twitter" aria-label="Permalink to &quot;Twitter&quot;">​</a></h4><ul><li><a href="https://twitter.com/NetPreserve" target="_blank" rel="noreferrer">@NetPreserve</a> - Official IIPC handle.</li><li><a href="https://twitter.com/WebSciDL" target="_blank" rel="noreferrer">@WebSciDL</a> - ODU Web Science and Digital Libraries Research Group.</li><li><a href="https://twitter.com/search?q=%23webarchiving" target="_blank" rel="noreferrer">#WebArchiving</a></li><li><a href="https://twitter.com/hashtag/webarchivewednesday" target="_blank" rel="noreferrer">#WebArchiveWednesday</a></li></ul>',39)])])}const m=r(o,[["render",l]]);export{g as __pageData,m as default};
